Here's a complete implementation:

**XAML — `ItemsPage.xaml`**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">

            <CollectionView.ItemsLayout>
                <LinearItemsLayout Orientation="Vertical"
                                   ItemSizingStrategy="MeasureFirstItem" />
            </CollectionView.ItemsLayout>

            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}"
                                   FontSize="12" TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>

            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>

        </CollectionView>
    </RefreshView>
</ContentPage>
```

**ViewModel — `ItemsViewModel.cs`**

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;

    public ItemsViewModel(IApiService api)
    {
        _api = api;
    }

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? _selectedItem;

    [ObservableProperty]
    private bool _isRefreshing;

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (SelectedItem is null) return;

        await Shell.Current.GoToAsync(
            $"{nameof(DetailPage)}?id={SelectedItem.Id}");

        // Reset so the same item can be re-selected later
        SelectedItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false;   // hides the spinner
        }
    }
}
```

**Key bindings explained:**

| XAML property | ViewModel property | Why |
|---|---|---|
| `IsRefreshing` | `bool IsRefreshing` | Two-way; set `false` when done to hide spinner |
| `Command` (RefreshView) | `RefreshCommand` | Generated by `[RelayCommand]` on `RefreshAsync` |
| `SelectedItem` | `Item? SelectedItem` | Two-way so you can null it after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap; navigates then clears selection |
| `ItemsSource` | `ObservableCollection<Item>` | Auto-updates UI on add/remove |

**Important details:**
- Wrap `CollectionView` in `RefreshView` — CollectionView has no built-in pull-to-refresh.
- Always set `IsRefreshing = false` in a `finally` block so the spinner stops even on errors.
- Null out `SelectedItem` after navigating so the user can tap the same item again.
- Use `ObservableCollection<T>`, never `List<T>` — otherwise the UI won't update.
- `MeasureFirstItem` improves scroll performance when items are uniform height.
